package com.mystreet.api.controller;
import com.mystreet.api.dto.Dto.OrderRequest;import com.mystreet.api.model.*;import com.mystreet.api.repo.*;import com.mystreet.api.security.AuthService;import jakarta.servlet.http.HttpServletRequest;import jakarta.validation.Valid;import lombok.RequiredArgsConstructor;import org.springframework.web.bind.annotation.*;import java.math.BigDecimal;import java.util.*;
@RestController @RequestMapping("/api/orders") @RequiredArgsConstructor
public class OrderController { private final OrderRepository orders; private final ProductRepository products; private final AuthService auth;
 @PostMapping Order create(@Valid @RequestBody OrderRequest r,HttpServletRequest req){ User user=auth.current(req); Order o=new Order();o.setUser(user);o.setShippingAddress(r.shippingAddress());o.setPaymentMode(r.paymentMode()); BigDecimal total=BigDecimal.ZERO; for(var line:r.items()){Product p=products.findById(line.productId()).orElseThrow(); if(p.getStockQty()<line.quantity()) throw new RuntimeException("Insufficient stock"); p.setStockQty(p.getStockQty()-line.quantity()); OrderItem item=new OrderItem();item.setOrder(o);item.setProduct(p);item.setSize(line.size());item.setQuantity(line.quantity());item.setPrice(p.getPrice());o.getItems().add(item);total=total.add(p.getPrice().multiply(BigDecimal.valueOf(line.quantity())));} o.setTotal(total);return orders.save(o);} 
 @GetMapping("/mine") List<Order> mine(HttpServletRequest req){ return orders.findAll().stream().filter(o->o.getUser().getId().equals(auth.current(req).getId())).toList();}
 @GetMapping("/{id}") Order one(@PathVariable UUID id,HttpServletRequest req){ User u=auth.current(req); Order o=orders.findById(id).orElseThrow(); if(!o.getUser().getId().equals(u.getId())&&!u.isAdmin()) throw new RuntimeException("Forbidden"); return o;}
}
